import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';
import { Form, Button, Container } from 'react-bootstrap';
import API_URL from '../config';

function EditEmployee() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [employee, setEmployee] = useState({ name: '', position: '', department: '' });

  useEffect(() => {
    axios.get(`${API_URL}/employees/${id}`, {
      headers: { "x-auth-token": localStorage.getItem("token") }
    })
    .then(response => setEmployee(response.data))
    .catch(error => console.error("Error fetching employee:", error));
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${API_URL}/employees/${id}`, employee, {
        headers: { "x-auth-token": localStorage.getItem("token") }
      });
      navigate('/employees');
    } catch (error) {
      console.error("Error updating employee:", error);
    }
  };

  return (
    <Container className="mt-5">
      <h2 className="text-center">Edit Employee</h2>
      <Form onSubmit={handleSubmit}>
        <Form.Group className="mb-3">
          <Form.Label>Name</Form.Label>
          <Form.Control type="text" value={employee.name} onChange={(e) => setEmployee({ ...employee, name: e.target.value })} required />
        </Form.Group>
        <Form.Group className="mb-3">
          <Form.Label>Position</Form.Label>
          <Form.Control type="text" value={employee.position} onChange={(e) => setEmployee({ ...employee, position: e.target.value })} required />
        </Form.Group>
        <Form.Group className="mb-3">
          <Form.Label>Department</Form.Label>
          <Form.Control type="text" value={employee.department} onChange={(e) => setEmployee({ ...employee, department: e.target.value })} required />
        </Form.Group>
        <Button variant="warning" type="submit" className="w-100">Update Employee</Button>
      </Form>
    </Container>
  );
}

export default EditEmployee;
